// 三载体一致:纯 JS 字符串输出,零 DOM/uplink/shadow 足迹
import * as opentype from 'https://cdn.jsdelivr.net/npm/opentype.js@2/+esm';
// v2 推荐路径:fetch 成 ArrayBuffer 再同步 parse(opentype.js@2 的 +esm 是 named-only,无 default 导出,故用 * as 命名空间导入,opentype.parse 照常可用)
const buf = await fetch(data.fontUrl).then(r => r.arrayBuffer());
const font = opentype.parse(buf);
const path = font.getPath(data.text, data.x ?? 0, data.y ?? (data.fontSize ?? 72), data.fontSize ?? 72);
const d = path.toPathData(2);        // 供 <path d=...>
const svgFragment = path.toSVG(2);    // '<path d=...>' 片段
const advance = font.getAdvanceWidth(data.text, data.fontSize ?? 72);
